sys_script.script:
(function executeRule(current, previous) {
    var passengerCount = parseInt(current.getValue('passenger_count'), 10);
    var fareAmount = parseFloat(current.getValue('fare_amount'));

    if (isNaN(passengerCount) || passengerCount <= 0) {
        gs.addErrorMessage('Passenger count must be greater than zero.');
        current.setAbortAction(true);
        return;
    }

    if (fareAmount < 0) {
        gs.addErrorMessage('Fare amount cannot be negative.');
        current.setAbortAction(true);
        return;
    }

    if (current.getValue('source_station') && current.getValue('destination_station')) {
        if (current.getValue('source_station') == current.getValue('destination_station')) {
            gs.addErrorMessage('Source and destination station cannot be the same.');
            current.setAbortAction(true);
            return;
        }
    }
})(current, previous);
